Feature Engineering

Speed & Acceleration

full_dataset &lt;- full_dataset |&gt;
  mutate(
    steplength = as.numeric(st_distance(lead(geom), geom, by_element = TRUE)),
    timelag = as.numeric(difftime(lead(datetime), datetime, units = "secs")),
    speed = steplength / timelag,
    acceleration = (lead(speed) - speed) / timelag,
    .by = track_id
  )

library(ggplot2)
library(forcats)

full_dataset |&gt;
  st_drop_geometry() |&gt;
  summarise(speed = mean(speed, na.rm = TRUE), .by = c(mode, track_id)) |&gt;
  mutate(mode = fct_reorder(mode, speed)) |&gt;
  ggplot() +
  geom_boxplot(aes(speed, mode, fill = mode)) +
  theme(legend.position = "none")







full_dataset |&gt;
  st_drop_geometry() |&gt;
  summarise(acceleration = mean(acceleration, na.rm = TRUE), .by = c(mode, track_id)) |&gt;
  mutate(mode = fct_reorder(mode, acceleration)) |&gt;
  ggplot() +
  geom_boxplot(aes(acceleration, mode, fill = mode)) +
  theme(legend.position = "none")










Sinuosity

library(zoo)

full_dataset &lt;- full_dataset |&gt;
  mutate(
    straight_dist5 = as.numeric(st_distance(lead(geom, 5), geom, by_element = TRUE)),
    full_dist5 = rollsum(steplength, 5, fill = NA, align = "left"),
    sinuosity = full_dist5 / straight_dist5,
    .by = track_id
  )



Turning Angle

full_dataset &lt;- full_dataset |&gt;
  arrange(track_id, datetime) |&gt;
  mutate(
    x = st_coordinates(geom)[,1],
    y = st_coordinates(geom)[,2]
  ) |&gt;
  mutate(
    dx = x - lag(x),
    dy = y - lag(y),
    direction = atan2(dy, dx),
    turning_angle = direction - lag(direction),
    turning_angle = atan2(sin(turning_angle), cos(turning_angle)),
    turning_angle = turning_angle * 180 / pi,
    .by = track_id
  )

full_dataset |&gt;
  st_drop_geometry() |&gt;
  summarise(turning_angle = mean(turning_angle, na.rm = TRUE), .by = c(mode, track_id)) |&gt;
  mutate(mode = fct_reorder(mode, turning_angle)) |&gt;
  ggplot() +
  geom_boxplot(aes(turning_angle, mode, fill = mode)) +
  theme(legend.position = "none")

Prepare Datasets

library(tidyr)

point_data &lt;- full_dataset |&gt;
  st_drop_geometry() |&gt;
  select(data, track_id, mode, datetime,
         steplength, timelag, speed, acceleration, sinuosity, turning_angle) |&gt;
  mutate(
    across(where(is.numeric), ~ ifelse(is.infinite(.x) | is.nan(.x), NA, .x)),
    mode = factor(mode)
  ) |&gt;
  drop_na(speed, acceleration, sinuosity, turning_angle)

point_training &lt;- point_data |&gt;
  filter(data == "training") |&gt;
  select(-data, -track_id, -datetime)

point_testing &lt;- point_data |&gt;
  filter(data == "testing") |&gt;
  select(-data, -track_id, -datetime)

point_validation &lt;- point_data |&gt;
  filter(data == "validation") |&gt;
  select(-data, -track_id, -datetime, -mode)
